import math

class HomieIndex:
    def __init__(self):
        self.docs = []
        self.features = []

    def _featurize(self, text):
        text = text.lower()
        if len(text) < 3:
            return {}
        out = {}
        for i in range(len(text) - 2):
            tri = text[i:i+3]
            out[tri] = out.get(tri, 0) + 1
        return out

    def add(self, text):
        self.docs.append(text)
        self.features.append(self._featurize(text))

    def _cosine(self, a, b):
        shared = set(a) & set(b)
        dot = sum(a[t] * b[t] for t in shared)
        ma = math.sqrt(sum(v**2 for v in a.values()))
        mb = math.sqrt(sum(v**2 for v in b.values()))
        if ma == 0 or mb == 0:
            return 0.0
        return dot / (ma * mb)

    def search(self, query, k=3):
        qf = self._featurize(query)
        scored = [(d, self._cosine(qf, f)) for d, f in zip(self.docs, self.features)]
        scored.sort(key=lambda x: -x[1])
        return scored[:k]

